  assign addrmiss = (reg_re || reg_we) ? ~|addr_hit : 1'b0 ;

  // Check sub-word write is permitted
  always_comb begin
    wr_err = (reg_we &
              ((addr_hit[ 0] & (|(BKDR_LOADER_REGS_PERMIT[ 0] & ~reg_be))) |
               (addr_hit[ 1] & (|(BKDR_LOADER_REGS_PERMIT[ 1] & ~reg_be))) |
               (addr_hit[ 2] & (|(BKDR_LOADER_REGS_PERMIT[ 2] & ~reg_be))) |
               (addr_hit[ 3] & (|(BKDR_LOADER_REGS_PERMIT[ 3] & ~reg_be))) |
               (addr_hit[ 4] & (|(BKDR_LOADER_REGS_PERMIT[ 4] & ~reg_be))) |
