               (addr_hit[25] & (|(BKDR_LOADER_REGS_PERMIT[25] & ~reg_be))) |
               (addr_hit[26] & (|(BKDR_LOADER_REGS_PERMIT[26] & ~reg_be))) |
               (addr_hit[27] & (|(BKDR_LOADER_REGS_PERMIT[27] & ~reg_be))) |
               (addr_hit[28] & (|(BKDR_LOADER_REGS_PERMIT[28] & ~reg_be))) |
