               (addr_hit[39] & (|(BKDR_LOADER_REGS_PERMIT[39] & ~reg_be))) |
               (addr_hit[40] & (|(BKDR_LOADER_REGS_PERMIT[40] & ~reg_be))) |
               (addr_hit[41] & (|(BKDR_LOADER_REGS_PERMIT[41] & ~reg_be))) |
