    reg_we_check[56] = index_we;
  end

  // Read data return
  always_comb begin
    reg_rdata_next = '0;
    unique case (1'b1)
      addr_hit[0]: begin
        reg_rdata_next[0] = status_target_error_qs;
        reg_rdata_next[1] = status_clear_idle_qs;
      end

      addr_hit[1]: begin
        reg_rdata_next[0] = control_done_qs;
        reg_rdata_next[1] = control_write_ena_qs;
        reg_rdata_next[2] = control_clear_start_qs;
        reg_rdata_next[15:8] = control_target_idx_qs;
      end

      addr_hit[2]: begin
        reg_rdata_next[31:0] = num_bkdr_targets_qs;
      end

      addr_hit[3]: begin
        reg_rdata_next[31:0] = usr_access_timestamp_qs;
      end

      addr_hit[4]: begin
        reg_rdata_next[31:0] = target_info_0_qs;
      end

      addr_hit[5]: begin
        reg_rdata_next[31:0] = target_info_1_qs;
      end

      addr_hit[6]: begin
        reg_rdata_next[31:0] = target_info_2_qs;
      end

      addr_hit[7]: begin
        reg_rdata_next[31:0] = target_info_3_qs;
      end

